mapper.select:
/* 장치구분별 알람건수 조회 */ select count( case when device_type = '1' then 1 end ) as pcs_cnt, /* PCS 건수 */ count( case when device_type = '2' then 1 end ) as bms_cnt, /* BMS 건수 */ count( case when device_type = '3' then 1 end ) as pv_cnt, /* PV 건수 */ count( case when device_type = '4' then 1 end ) as ioe_cnt, /* IOE 건수 */
count( case when device_type not in ('1', '2', '3', '4') then 1 end ) as etc_cnt, /* 기타 건수 */ count( case when alarm_type = '1' then 1 end ) as warning_cnt, /* 비상 건수 */ count( case when alarm_type = '2' then 1 end ) as alert_cnt, /* 주의 건수 */ count( case when alarm_cfm_yn = 'N' then 1 end ) as notCfm_cnt, /* 미확인 건수 */ count(*) as total_cnt /* 총 건수 */ from ( select a.alarm_idx, a.site_id, a.device_id, a.device_type, a.std_date, a.alarm_type, a.alarm_msg, a.alarm_cfm_yn, a.alarm_cfm_date, a.alarm_cfm_uid, a.alarm_act_yn, a.alarm_note, a.reg_date, a.mod_date from tb_alarm a, tb_device b where a.device_id = b.device_id and a.site_id = b.site_id and a.device_type = b.device_type
and a.site_id = #{siteId }
and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
) a

/* 사이트메인 장치타입별 알람건수 조회 */ select count( case when alarm_type = '1' then 1 end ) as warning_cnt, /* 비상 건수 */ count( case when alarm_type = '2' then 1 end ) as alert_cnt /* 주의 건수 */ from tb_alarm a, tb_device b where a.device_id = b.device_id and a.site_id = b.site_id and a.device_type = b.device_type
and a.site_id = #{siteId }
and a.alarm_act_yn = 'N'

/* 알람 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select
				a.alarm_idx, a.site_id, a.device_id, b.device_name, a.device_type, 
				case a.device_type when 1 then 'PCS'
					when 2 then 'BMS'
					when 3 then 'PV'
					when 4 then '부하측정기기'
					when 5 then 'PV모니터링기기'
					else 'ESS모니터링기기' end as device_type_nm,
				a.std_date, a.alarm_code, a.alarm_type, a.alarm_msg, 
				a.alarm_cfm_yn, a.alarm_cfm_date, a.alarm_cfm_uid, a.alarm_act_yn, a.alarm_note, a.reg_date, a.mod_date
			from tb_alarm a, tb_device b
			where a.device_id = b.device_id
			and a.site_id = b.site_id
			and a.device_type = b.device_type
			
			and a.site_id = #{siteId }
			
			and a.alarm_type = #{alarmType }
			
			and a.std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
			
			order by a.std_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb
limit #{startNum }, #{pageRowCnt }

/* 알람 목록 건수 조회 */
select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select
				a.alarm_idx, a.site_id, a.device_id, b.device_name, a.device_type, 
				case a.device_type when 1 then 'PCS'
					when 2 then 'BMS'
					when 3 then 'PV'
					when 4 then '부하측정기기'
					when 5 then 'PV모니터링기기'
					else 'ESS모니터링기기' end as device_type_nm,
				a.std_date, a.alarm_code, a.alarm_type, a.alarm_msg, 
				a.alarm_cfm_yn, a.alarm_cfm_date, a.alarm_cfm_uid, a.alarm_act_yn, a.alarm_note, a.reg_date, a.mod_date
			from tb_alarm a, tb_device b
			where a.device_id = b.device_id
			and a.site_id = b.site_id
			and a.device_type = b.device_type
			
			and a.site_id = #{siteId }
			
			and a.alarm_type = #{alarmType }
			
			and a.std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
			
			order by a.std_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

/* 장치구분별 알람건수 조회 */
select 
	count( case when device_type = '1' then 1 end ) as pcs_cnt, /* PCS 건수 */
	count( case when device_type = '2' then 1 end ) as bms_cnt, /* BMS 건수 */
	count( case when device_type = '3' then 1 end ) as pv_cnt, /* PV 건수 */
	count( case when device_type = '4' then 1 end ) as ioe_cnt, /* IOE 건수 */
	
	count( case when device_type not in ('1', '2', '3', '4') then 1 end ) as etc_cnt, /* 기타 건수 */
	count( case when alarm_type = '1' then 1 end ) as warning_cnt, /* 비상 건수 */
	count( case when alarm_type = '2' then 1 end ) as alert_cnt, /* 주의 건수 */
	count( case when alarm_cfm_yn = 'N' then 1 end ) as notCfm_cnt, /* 미확인 건수 */
	count(*) as total_cnt /* 총 건수 */
from (
		select
			a.alarm_idx, a.site_id, a.device_id, a.device_type, a.std_date, a.alarm_code, a.alarm_type, a.alarm_msg,
			a.alarm_cfm_yn, a.alarm_cfm_date, a.alarm_cfm_uid, a.alarm_act_yn, a.alarm_note, a.reg_date, a.mod_date
		from tb_alarm a, tb_site b, tb_site_group c, tb_device d
		where 1=1
		and a.site_id = b.site_id
		and b.site_grp_idx = c.site_grp_idx
		and a.device_id = d.device_id
		and a.site_id = d.site_id
		and a.device_type = d.device_type
		
		
		
		and b.user_idx = #{userIdx}
		
		
		and b.comp_idx = #{compIdx}
		
		
		and b.site_grp_idx = #{siteGrpIdx}
		
		and b.area_type = #{areaType}
		
		
		
		and c.site_grp_idx = #{grpIdx}
		
		
		and c.user_idx = #{userIdx}
		
		
		and c.comp_idx = #{compIdx}
		
		
		and c.site_grp_idx = #{siteGrpIdx}
		
		
		
		
		and a.std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
		
) f_tb

/* 군관리메인 장치타입별 알람건수 조회 */
select
	count( case when alarm_type = '1' then 1 end ) as warning_cnt, /* 비상 건수 */
	count( case when alarm_type = '2' then 1 end ) as alert_cnt /* 주의 건수 */
from tb_alarm a, tb_site b, tb_site_group c, tb_device d
where 1=1
and a.site_id = b.site_id
and b.site_grp_idx = c.site_grp_idx
and a.device_id = d.device_id
and a.site_id = d.site_id
and a.device_type = d.device_type



and b.user_idx = #{userIdx}


and b.comp_idx = #{compIdx}


and b.site_grp_idx = #{siteGrpIdx}

and b.area_type = #{areaType}



and c.site_grp_idx = #{grpIdx}


and c.user_idx = #{userIdx}


and c.comp_idx = #{compIdx}


and c.site_grp_idx = #{siteGrpIdx}



and a.alarm_act_yn = 'N'

/* 장치구분별 알람건수 조회 */ select count( case when device_type = '1' then 1 end ) as pcs_cnt, /* PCS 건수 */ count( case when device_type = '2' then 1 end ) as bms_cnt, /* BMS 건수 */ count( case when device_type = '3' then 1 end ) as pv_cnt, /* PV 건수 */ count(*) as total_cnt /* 총 건수 */ from ( select a.alarm_idx, a.site_id, a.device_id, a.device_type, a.std_date, a.alarm_type, a.alarm_msg, a.alarm_cfm_yn, a.alarm_cfm_date, a.alarm_cfm_uid, a.alarm_act_yn, a.alarm_note, a.reg_date, a.mod_date from tb_alarm a, tb_device b where a.device_id = b.device_id and a.site_id = b.site_id and a.device_type = b.device_type
and a.site_id = #{siteId }
and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')
) a

/* 알람 수신자 목록 조회 */
select 
	sms_user_idx, site_id, `name` as addressee_name, mobile, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_sms_user
where del_yn = 'N'

and site_id = #{siteId }
